    public void handleTicker(Client client, Object message)
    {
        //
        //     {
        //         "arg": { channel: "tickers", instId: "BTC-USDT" },
        //         "data": [
        //             {
        //                 "instType": "SPOT",
        //                 "instId": "BTC-USDT",
        //                 "last": "31500.1",
        //                 "lastSz": "0.00001754",
        //                 "askPx": "31500.1",
        //                 "askSz": "0.00998144",
        //                 "bidPx": "31500",
        //                 "bidSz": "3.05652439",
        //                 "open24h": "31697",
        //                 "high24h": "32248",
        //                 "low24h": "31165.6",
        //                 "sodUtc0": "31385.5",
        //                 "sodUtc8": "32134.9",
        //                 "volCcy24h": "503403597.38138519",
        //                 "vol24h": "15937.10781721",
        //                 "ts": "1626526618762"
        //             }
        //         ]
        //     }
        //
        this.handleBidAsk(client, message);
        Object arg = this.safeValue(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object marketId = this.safeString(arg, "instId");
        Object market = this.safeMarket(marketId, null, "-");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object channel = this.safeString(arg, "channel");
        Object data = this.safeValue(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object newTickers = new java.util.HashMap<String, Object>() {{}};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object ticker = this.parseTicker(Helpers.GetValue(data, i));
            Helpers.addElementToObject(this.tickers, symbol, ticker);
            Helpers.addElementToObject(newTickers, symbol, ticker);
        }
        Object messageHash = Helpers.add(Helpers.add(channel, "::"), symbol);
        client.resolve(newTickers, messageHash);
    }

