    public void handleOHLCV(Client client, Object message)
    {
        //
        //     {
        //         "arg": { channel: "candle1m", instId: "BTC-USDT" },
        //         "data": [
        //             [
        //                 "1626690720000",
        //                 "31334",
        //                 "31334",
        //                 "31334",
        //                 "31334",
        //                 "0.0077",
        //                 "241.2718"
        //             ]
        //         ]
        //     }
        //
        Object arg = this.safeValue(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object channel = this.safeString(arg, "channel");
        Object data = this.safeValue(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object marketId = this.safeString(arg, "instId");
        Object market = this.safeMarket(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object interval = Helpers.replace((String)channel, (String)"candle", (String)"");
        // use a reverse lookup in a static map instead
        Object timeframe = this.findTimeframe(interval);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object parsed = this.parseOHLCV(Helpers.GetValue(data, i), market);
            Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
            Object stored = this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
            if (Helpers.isTrue(Helpers.isEqual(stored, null)))
            {
                Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
                stored = new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue());
                Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, stored);
            }
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
            Object messageHash = Helpers.add(Helpers.add(channel, ":"), Helpers.GetValue(market, "id"));
            client.resolve(stored, messageHash);
            // for multiOHLCV we need special object, as opposed to other "multi"
            // methods, because OHLCV response item does not contain symbol
            // or timeframe, thus otherwise it would be unrecognizable
            Object messageHashForMulti = Helpers.add(Helpers.add(Helpers.add("multi:", channel), ":"), symbol);
            client.resolve(new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol, timeframe, stored)), messageHashForMulti);
        }
    }

    /**
     * @method
     * @name okx#watchOrderBook
     * @see https://www.okx.com/docs-v5/en/#order-book-trading-market-data-ws-order-book-channel
     * @description watches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.depth] okx order book depth, can be books, books5, books-l2-tbt, books50-l2-tbt, bbo-tbt
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            //
            // bbo-tbt
            // 1. Newly added channel that sends tick-by-tick Level 1 data
            // 2. All API users can subscribe
            // 3. Public depth channel, verification not required
            //
            // books-l2-tbt
            // 1. Only users who're VIP5 and above can subscribe
            // 2. Identity verification required before subscription
            //
            // books50-l2-tbt
            // 1. Only users who're VIP4 and above can subscribe
            // 2. Identity verification required before subscription
            //
            // books
            // 1. All API users can subscribe
            // 2. Public depth channel, verification not required
            //
            // books5
            // 1. All API users can subscribe
            // 2. Public depth channel, verification not required
            // 3. Data feeds will be delivered every 100ms (vs. every 200ms now)
            //
            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            return (this.watchOrderBookForSymbols(new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol)), limit, parameters)).join();
        });

    }

    /**
     * @method
     * @name okx#watchOrderBookForSymbols
     * @see https://www.okx.com/docs-v5/en/#order-book-trading-market-data-ws-order-book-channel
     * @description watches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @param {string[]} symbols unified array of symbols
     * @param {int} [limit] 1,5, 400, 50 (l2-tbt, vip4+) or 40000 (vip5+) the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.depth] okx order book depth, can be books, books5, books-l2-tbt, books50-l2-tbt, bbo-tbt
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrderBookForSymbols(Object symbols2, Object... optionalArgs)
    {
        final Object symbols3 = symbols2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object symbols = symbols3;
            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            symbols = this.marketSymbols(symbols);
            Object depth = null;
            var depthparametersVariable = this.handleOptionAndParams(parameters, "watchOrderBook", "depth", "books");
            depth = ((java.util.List<Object>) depthparametersVariable).get(0);
            parameters = ((java.util.List<Object>) depthparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                if (Helpers.isTrue(Helpers.isEqual(limit, 1)))
                {
                    depth = "bbo-tbt";
                } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isGreaterThan(limit, 1)) && Helpers.isTrue(Helpers.isLessThanOrEqual(limit, 5))))
                {
                    depth = "books5";
                } else if (Helpers.isTrue(Helpers.isEqual(limit, 50)))
                {
                    depth = "books50-l2-tbt"; // Make sure you have VIP4 and above
                } else if (Helpers.isTrue(Helpers.isEqual(limit, 400)))
                {
                    depth = "books";
                }
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(depth, "books-l2-tbt"))) || Helpers.isTrue((Helpers.isEqual(depth, "books50-l2-tbt")))))
            {
                if (!Helpers.isTrue(this.checkRequiredCredentials(false)))
                {
                    throw new AuthenticationError((String)Helpers.add(this.id, " watchOrderBook/watchOrderBookForSymbols requires authentication for this depth. Add credentials or change the depth option to books or books5")) ;
                }
                (this.authenticate(new java.util.HashMap<String, Object>() {{
                    put( "access", "public" );
                }})).join();
            }
            Object topics = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
            {
                Object symbol = Helpers.GetValue(symbols, i);
                ((java.util.List<Object>)messageHashes).add(Helpers.add(Helpers.add(depth, ":"), symbol));
                Object marketId = this.marketId(symbol);
                final Object finalDepth = depth;
                Object topic = new java.util.HashMap<String, Object>() {{
                    put( "channel", finalDepth );
                    put( "instId", marketId );
                }};
                ((java.util.List<Object>)topics).add(topic);
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "op", "subscribe" );
                put( "args", topics );
            }};
            Object url = this.getUrl(depth, "public");
            Object orderbook = (this.watchMultiple(url, messageHashes, request, messageHashes, null)).join();
            return Helpers.callDynamically(orderbook, "limit", new Object[]{});
        });

    }

