    public void handleDelta(Object bookside, Object delta)
    {
        //
        //     [
        //         "31685", // price
        //         "0.78069158", // amount
        //         "0", // liquidated orders
        //         "17" // orders
        //     ]
        //
        Object price = this.safeFloat(delta, 0);
        Object amount = this.safeFloat(delta, 1);
        Helpers.callDynamically(bookside, "store", new Object[]{price, amount});
    }

    public void handleDeltas(Object bookside, Object deltas)
    {
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(deltas)); i++)
        {
            this.handleDelta(bookside, Helpers.GetValue(deltas, i));
        }
    }

    public Object handleOrderBookMessage(Client client, Object message, Object orderbook, Object messageHash, Object... optionalArgs)
    {
        //
        //     {
        //         "asks": [
        //             [ '31738.3', '0.05973179', "0", "3" ],
        //             [ '31738.5', '0.11035404', "0", "2" ],
        //             [ '31739.6', '0.01', "0", "1" ],
        //         ],
        //         "bids": [
        //             [ '31738.2', '0.67557666', "0", "9" ],
        //             [ '31738', '0.02466947', "0", "2" ],
        //             [ '31736.3', '0.01705046', "0", "2" ],
        //         ],
        //         "instId": "BTC-USDT",
        //         "ts": "1626537446491"
        //         "checksum": -855196043,
        //         "prevSeqId": 123456,
        //         "seqId": 123457
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object asks = this.safeValue(message, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object bids = this.safeValue(message, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object storedAsks = Helpers.GetValue(orderbook, "asks");
        Object storedBids = Helpers.GetValue(orderbook, "bids");
        this.handleDeltas(storedAsks, asks);
        this.handleDeltas(storedBids, bids);
        Object marketId = this.safeString(message, "instId");
        Object symbol = this.safeSymbol(marketId, market);
        Object seqId = this.safeInteger(message, "seqId");
        Object prevSeqId = this.safeInteger(message, "prevSeqId");
        Object nonce = Helpers.GetValue(orderbook, "nonce");
        Object error = null;
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(prevSeqId, null)) && Helpers.isTrue(!Helpers.isEqual(prevSeqId, Helpers.opNeg(1)))) && Helpers.isTrue(!Helpers.isEqual(nonce, prevSeqId))))
        {
            error = new InvalidNonce(Helpers.add(this.id, " watchOrderBook received invalid nonce"));
        }
        if (Helpers.isTrue(!Helpers.isEqual(error, null)))
        {
            ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                ((java.util.Map<String,Object>)this.orderbooks).remove((String)symbol);
            }
            client.reject(error, messageHash);
        }
        Object timestamp = this.safeInteger(message, "ts");
        Helpers.addElementToObject(orderbook, "nonce", seqId);
        Helpers.addElementToObject(orderbook, "timestamp", timestamp);
        Helpers.addElementToObject(orderbook, "datetime", this.iso8601(timestamp));
        return orderbook;
    }

    public Object handleOrderBook(Client client, Object message)
    {
        //
        // snapshot
        //
        //     {
        //         "arg": { channel: 'books-l2-tbt', instId: "BTC-USDT" },
        //         "action": "snapshot",
        //         "data": [
        //             {
        //                 "asks": [
        //                     [ '31685', '0.78069158', "0", "17" ],
        //                     [ '31685.1', '0.0001', "0", "1" ],
        //                     [ '31685.6', '0.04543165', "0", "1" ],
        //                 ],
        //                 "bids": [
        //                     [ '31684.9', '0.01', "0", "1" ],
        //                     [ '31682.9', '0.0001', "0", "1" ],
        //                     [ '31680.7', '0.01', "0", "1" ],
        //                 ],
        //                 "ts": "1626532416403",
        //                 "checksum": -1023440116
        //             }
        //         ]
        //     }
        //
        // update
        //
        //     {
        //         "arg": { channel: 'books-l2-tbt', instId: "BTC-USDT" },
        //         "action": "update",
        //         "data": [
        //             {
        //                 "asks": [
        //                     [ '31657.7', '0', "0", "0" ],
        //                     [ '31659.7', '0.01', "0", "1" ],
        //                     [ '31987.3', '0.01', "0", "1" ]
        //                 ],
        //                 "bids": [
        //                     [ '31642.9', '0.50296385', "0", "4" ],
        //                     [ '31639.9', '0', "0", "0" ],
        //                     [ '31638.7', '0.01', "0", "1" ],
        //                 ],
        //                 "ts": "1626535709008",
        //                 "checksum": 830931827
        //             }
        //         ]
        //     }
        //
        // books5
        //
        //     {
        //         "arg": { channel: "books5", instId: "BTC-USDT" },
        //         "data": [
        //             {
        //                 "asks": [
        //                     [ '31738.3', '0.05973179', "0", "3" ],
        //                     [ '31738.5', '0.11035404', "0", "2" ],
        //                     [ '31739.6', '0.01', "0", "1" ],
        //                 ],
        //                 "bids": [
        //                     [ '31738.2', '0.67557666', "0", "9" ],
        //                     [ '31738', '0.02466947', "0", "2" ],
        //                     [ '31736.3', '0.01705046', "0", "2" ],
        //                 ],
        //                 "instId": "BTC-USDT",
        //                 "ts": "1626537446491"
        //             }
        //         ]
        //     }
        //
        // bbo-tbt
        //
        //     {
        //         "arg":{
        //             "channel":"bbo-tbt",
        //             "instId":"BTC-USDT"
        //         },
        //         "data":[
        //             {
        //                 "asks":[["36232.2","1.8826134","0","17"]],
        //                 "bids":[["36232.1","0.00572212","0","2"]],
        //                 "ts":"1651826598363"
        //             }
        //         ]
        //     }
        //
        Object arg = this.safeDict(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object channel = this.safeString(arg, "channel");
        Object action = this.safeString(message, "action");
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object marketId = this.safeString(arg, "instId");
        Object market = this.safeMarket(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object depths = new java.util.HashMap<String, Object>() {{
            put( "bbo-tbt", 1 );
            put( "books", 400 );
            put( "books5", 5 );
            put( "books-l2-tbt", 400 );
            put( "books50-l2-tbt", 50 );
        }};
        Object limit = this.safeInteger(depths, channel);
        Object messageHash = Helpers.add(Helpers.add(channel, ":"), symbol);
        if (Helpers.isTrue(Helpers.isEqual(action, "snapshot")))
        {
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object update = Helpers.GetValue(data, i);
                Object orderbook = this.orderBook(new java.util.HashMap<String, Object>() {{}}, limit);
                Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
                Helpers.addElementToObject(orderbook, "symbol", symbol);
                this.handleOrderBookMessage(client, update, orderbook, messageHash);
                client.resolve(orderbook, messageHash);
            }
        } else if (Helpers.isTrue(Helpers.isEqual(action, "update")))
        {
            if (Helpers.isTrue(Helpers.inOp(this.orderbooks, symbol)))
            {
                Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
                {
                    Object update = Helpers.GetValue(data, i);
                    this.handleOrderBookMessage(client, update, orderbook, messageHash, market);
                    client.resolve(orderbook, messageHash);
                }
            }
        } else if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(channel, "books5"))) || Helpers.isTrue((Helpers.isEqual(channel, "bbo-tbt")))))
        {
            if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
            {
                Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, limit));
            }
            Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object update = Helpers.GetValue(data, i);
                Object timestamp = this.safeInteger(update, "ts");
                Object snapshot = this.parseOrderBook(update, symbol, timestamp, "bids", "asks", 0, 1);
                Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
                client.resolve(orderbook, messageHash);
            }
        }
        return message;
    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.checkRequiredCredentials();
            Object access = this.safeString(parameters, "access", "private");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("access")));
            Object url = this.getUrl("users", access);
            Object messageHash = "authenticated";
            Client client = this.client(url);
            io.github.ccxt.ws.Future future = client.reusableFuture((String)messageHash);
            Object authenticated = this.safeValue(client.subscriptions, messageHash);
            if (Helpers.isTrue(Helpers.isEqual(authenticated, null)))
            {
                Object timestamp = String.valueOf(this.seconds());
                Object method = "GET";
                Object path = "/users/self/verify";
                Object auth = Helpers.add(Helpers.add(timestamp, method), path);
                Object signature = this.hmac(this.encode(auth), this.encode(this.secret), sha256(), "base64");
                Object operation = "login";
                final Object finalTimestamp = timestamp;
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "op", operation );
                    put( "args", new java.util.ArrayList<Object>(java.util.Arrays.asList(new java.util.HashMap<String, Object>() {{
        put( "apiKey", OkxCore.this.apiKey );
        put( "passphrase", OkxCore.this.password );
        put( "timestamp", finalTimestamp );
        put( "sign", signature );
    }})) );
                }};
                // Only add params['access'] to prevent sending custom parameters, such as extraParams.
                if (Helpers.isTrue(Helpers.inOp(parameters, "access")))
                {
                    Helpers.addElementToObject(request, "access", Helpers.GetValue(parameters, "access"));
                }
                this.watch(url, messageHash, request, messageHash, null);
            }
            return ((io.github.ccxt.ws.Future)future).getFuture().join();
        });

    }

