    public Object orderToTrade(Object order, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object info = this.safeValue(order, "info", new java.util.HashMap<String, Object>() {{}});
        Object timestamp = this.safeInteger(info, "fillTime");
        Object feeMarketId = this.safeString(info, "fillFeeCcy");
        Object isTaker = Helpers.isEqual(this.safeString(info, "execType", ""), "T");
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
            put( "symbol", OkxCore.this.safeString(order, "symbol") );
            put( "id", OkxCore.this.safeString(info, "tradeId") );
            put( "order", OkxCore.this.safeString(order, "id") );
            put( "type", OkxCore.this.safeString(order, "type") );
            put( "takerOrMaker", ((Helpers.isTrue((isTaker)))) ? "taker" : "maker" );
            put( "side", OkxCore.this.safeString(order, "side") );
            put( "price", OkxCore.this.safeNumber(info, "fillPx") );
            put( "amount", OkxCore.this.safeNumber(info, "fillSz") );
            put( "cost", OkxCore.this.safeNumber(order, "cost") );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", OkxCore.this.safeNumber(info, "fillFee") );
                put( "currency", OkxCore.this.safeCurrencyCode(feeMarketId) );
            }} );
        }}, market);
    }

    /**
     * @method
     * @name okx#watchMyTrades
     * @description watches information on multiple trades made by the user
     * @see https://www.okx.com/docs-v5/en/#order-book-trading-trade-ws-order-channel
     * @param {string} [symbol] unified market symbol of the market trades were made in
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trade structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {bool} [params.trigger] true if fetching trigger or conditional trades
     * @param {string} [params.type] 'spot', 'swap', 'future', 'option', 'ANY', 'SPOT', 'MARGIN', 'SWAP', 'FUTURES' or 'OPTION'
     * @param {string} [params.marginMode] 'cross' or 'isolated', for automatically setting the type to spot margin
     * @returns {object[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // By default, receive order updates from any instrument type
            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            Object type = null;
            var typeparametersVariable = this.handleOptionAndParams(parameters, "watchMyTrades", "type", "ANY");
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            Object isTrigger = this.safeBool2(parameters, "trigger", "stop", false);
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("trigger", "stop")));
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            (this.authenticate(new java.util.HashMap<String, Object>() {{
                put( "access", ((Helpers.isTrue(isTrigger))) ? "business" : "private" );
            }})).join();
            Object channel = ((Helpers.isTrue(isTrigger))) ? "orders-algo" : "orders";
            Object messageHash = Helpers.add(channel, "::myTrades");
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                symbol = Helpers.GetValue(market, "symbol");
                type = Helpers.GetValue(market, "type");
                messageHash = Helpers.add(Helpers.add(messageHash, "::"), symbol);
            }
            if (Helpers.isTrue(Helpers.isEqual(type, "future")))
            {
                type = "futures";
            }
            Object uppercaseType = ((String)type).toUpperCase();
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("watchMyTrades", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(uppercaseType, "SPOT")))
            {
                if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
                {
                    uppercaseType = "MARGIN";
                }
            }
            final Object finalUppercaseType = uppercaseType;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instType", finalUppercaseType );
            }};
            Object orders = (this.subscribe("private", messageHash, channel, null, this.extend(request, parameters))).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(orders, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(orders, symbol, since, limit, true);
        });

    }

    /**
     * @method
     * @name okx#watchPositions
     * @see https://www.okx.com/docs-v5/en/#trading-account-websocket-positions-channel
     * @description watch all open positions
     * @param {string[]} [symbols] list of unified market symbols
     * @param {int} [since] timestamp in ms of the earliest position to fetch
     * @param {int} [limit] the maximum number of positions to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [position structure]{@link https://docs.ccxt.com/en/latest/manual.html#position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            (this.authenticate(parameters)).join();
            symbols = this.marketSymbols(symbols);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instType", "ANY" );
            }};
            Object channel = "positions";
            Object newPositions = null;
            if (Helpers.isTrue(Helpers.isEqual(symbols, null)))
            {
                Object arg = new java.util.HashMap<String, Object>() {{
                    put( "channel", "positions" );
                    put( "instType", "ANY" );
                }};
                Object args = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.extend(arg, parameters)));
                Object nonSymbolRequest = new java.util.HashMap<String, Object>() {{
                    put( "op", "subscribe" );
                    put( "args", args );
                }};
                Object url = this.getUrl(channel, "private");
                newPositions = (this.watch(url, channel, nonSymbolRequest, channel, null)).join();
            } else
            {
                newPositions = (this.subscribeMultiple("private", channel, symbols, this.extend(request, parameters))).join();
            }
            if (Helpers.isTrue(this.newUpdates))
            {
                return newPositions;
            }
            return this.filterBySymbolsSinceLimit(this.positions, symbols, since, limit, true);
        });

    }

